if length entries == 0 then ("", "", "", "", "")
else
  let (n, mp, ap, port, ml) = parse_model (head entries)
  if n == name then (n, mp, ap, port, ml)
  else find_model name (tail entries)

let _ = log (cat ["Starting self_train on Mini (port ", show port, ")..."])
let pid = trim (shell (cat ["nohup ./rail_native_llm run tools/train/self_train.rail --port ", show port, " --no-retrain yes > /tmp/waterfall_selftrain.log 2>&1 & echo $!"]))
let _ = write_pid "selftrain" pid
log (cat ["  PID: ", pid])

let _w_val = head captures
let ids_val = head (tail captures)
let vocab_size_tensor = head (tail (tail captures))
let vocab_size = tensor_to_int vocab_size_tensor
let embed_dim = last_dim (tensor_shape upstream)
-- Create zero gradient matrix of shape [vocab_size, embed_dim]
let dw = tensor_zeros [vocab_size, embed_dim]
-- Scatter-add: for each position, accumulate upstream[pos,:] into dw[id,:]
let dw2 = ag_scatter_add dw ids_val upstream 0
[dw2]

if length acc == 0 then []
else if length row == 0 then acc
else cons (max_int (head acc) (length (head row))) (merge_widths (tail acc) (tail row))

if i >= n then 0
else
  let hi = hex_val (head (chars (str_sub hex (i * 2) 1)))
  let lo = hex_val (head (chars (str_sub hex (i * 2 + 1) 1)))
  let _ = float_arr_set arr i (to_float (hi * 16 + lo))
  read_binary_fill arr hex n (i + 1)

if length cs == 0 then false
else if matches_prefix nc cs then true
else has_substr_loop nc (tail cs)

if length cs == 0 then []
else
  let c = head cs
  if c == " " then trim_ws_chars_left (tail cs)
  else if c == "\n" then trim_ws_chars_left (tail cs)
  else if c == "\t" then trim_ws_chars_left (tail cs)
  else if c == "\r" then trim_ws_chars_left (tail cs)
  else cs

if length xs == 0 then cur
else if head xs < cur then min_loop (tail xs) (head xs)
else min_loop (tail xs) cur

let _ = kill_gpu 0
let has_adapter = trim (shell (cat ["test -f ", adapter_dir, "/adapters.safetensors && echo yes || echo no"]))
let adapter_flag = if has_adapter == "yes" then cat [" --adapter-path ", adapter_dir] else ""
let cmd = cat [mlx_python, " -m mlx_lm.server --model ", model_path, adapter_flag, " --host 0.0.0.0 --port ", port, " --trust-remote-code --max-tokens 2048"]
let _ = shell (cat ["nohup ", cmd, " > /tmp/rail_mlx_server.log 2>&1 &"])
let _ = hyper_log (cat ["Starting MLX server on :", port, if has_adapter == "yes" then " (adapter)" else " (base)"])
wait_server port 0

let exists = trim (shell (cat ["test -f ", state_path, " && echo yes || echo no"]))
if exists == "yes" then
  let cycle_s = trim (shell (cat ["jq -r '.cycle // 0' ", state_path, " 2>/dev/null"]))
  let best_s = trim (shell (cat ["jq -r '.best_score // 0' ", state_path, " 2>/dev/null"]))
  let gen_s = trim (shell (cat ["jq -r '.best_gen // 0' ", state_path, " 2>/dev/null"]))
  (parse_int cycle_s, parse_int best_s, parse_int gen_s)
else (0, 0, 0)

let src_hash = trim (shell "md5 -q tools/train/self_train.rail 2>/dev/null || md5sum tools/train/self_train.rail | cut -d' ' -f1")
let old_hash = trim (shell "cat /tmp/rail_st_hash 2>/dev/null || echo none")
let has_bin = trim (shell "test -f /tmp/rail_st_bin && echo yes || echo no")
if src_hash == old_hash then
  if has_bin == "yes" then 0
  else 1
else 1

if i >= N then 0
else
  let target = float_to_int (float_arr_get ld i)
  let p = float_arr_get pd (i * C + target)
  let p2 = if p < 0.00000001 then 0.00000001 else p
  let cur = float_arr_get acc 0
  let _ = float_arr_set acc 0 (cur - log p2)
  ce_loop pd ld N C acc (i + 1)
